    SELECT goods_id, stock FROM inventory WHERE goods_id = #{goodsId}
</select>
<update id="deductStock">
    UPDATE inventory SET stock = stock - #{deductCount} WHERE goods_id = #{goodsId}
</update>
<update id="addStock">
    UPDATE inventory SET stock = stock + 50 WHERE goods_id = #{goodsId}
</update>
```
